local dragging = false
local minSize = 2  -- Стандарт
local maxSize = 50 -- Максимальний розмір

local function updateHitbox(size)
	local char = game.Players.LocalPlayer.Character
	if char and char:FindFirstChild("HumanoidRootPart") then
		local hrp = char.HumanoidRootPart
		hrp.Size = Vector3.new(size, size, size)
		hrp.Transparency = 0.7
		hrp.Color = Color3.new(0, 1, 0.5) -- Світло-зелений для візуалізації
		hrp.CanCollide = false
		valueLabel.Text = "Розмір: " .. string.format("%.1f", size)
	end
end

sliderBtn.MouseButton1Down:Connect(function()
	dragging = true
end)

UserInputService.InputEnded:Connect(function(input)
	if input.UserInputType == Enum.UserInputType.MouseButton1 then
		dragging = false
	end
end)

UserInputService.InputChanged:Connect(function(input)
	if dragging and input.UserInputType == Enum.UserInputType.MouseMovement then
		local mousePos = UserInputService:GetMouseLocation().X
		local sliderPos = sliderBack.AbsolutePosition.X
		local sliderWidth = sliderBack.AbsoluteSize.X
		
		-- Обчислюємо відсоток (від 0 до 1)
		local percent = math.clamp((mousePos - sliderPos) / sliderWidth, 0, 1)
		sliderBtn.Position = UDim2.new(percent, -10, 0.5, -15)
		
		-- Розраховуємо реальний розмір на основі відсотка
		local newSize = minSize + (percent * (maxSize - minSize))
		updateHitbox(newSize)
	end
end)
